size(6cm);defaultpen(fontsize(11));
pair b =(0,0);pair c = (10, 0);pair a=(4, 6);
pair d= midpoint(b--c);
pair e = a + (1/3) * (c - a);
pair f = d + 0.25 * (a - d);
draw(a--b--c--cycle--d--e--f);

label("$A$", a, N);
label("$B$", b, SW);
label("$C$", c, SE);
label("$D$", d, S);
label("$E$", e, NE);
label("$F$", f, SW);
[/asy]

